\nimport SwiftUI\n\nstruct OrganizerWizardView: View {\n    @StateObject private var viewModel = OrganizerWizardViewModel()\n    @Binding var isPresented: Bool\n    \n    // File Importer states\n    @State private var showSourceImporter = false\n    @State private var showDestinationImporter = false\n\n    var body: some View {\n        VStack(spacing: 0) {\n            // Header\n            Text(\"✨ Assistente de Organização\")\n                .font(.largeTitle)\n                .fontWeight(.bold)\n                .padding()\n                .frame(maxWidth: .infinity)\n                .background(Color(.windowBackgroundColor))\n                .overlay(alignment: .topTrailing) {\n                    Button(action: { isPresented = false }) {\n                        Image(systemName: \"xmark.circle.fill\")\n                            .font(.title2)\n                            .foregroundColor(.gray)\n                    }\n                    .buttonStyle(.plain)\n                    .padding()\n                }\n\n            Divider()\n\n            // Main content based on step\n            Group {\n                switch viewModel.currentStep {\n                case .selectSourceAndDestination:\n                    step1_SelectSourceAndDestination()\n                case .chooseActionAndRules:\n                    step2_ChooseActionAndRules()\n                case .preview:\n                    step3_Preview()\n                case .progress:\n                    step4_Progress()\n                case .complete:\n                    step5_Complete()\n                }\n            }\n            .frame(maxWidth: .infinity, maxHeight: .infinity)\n        }\n        .frame(width: 500, height: 550)\n        .fileImporter(isPresented: $showSourceImporter, allowedContentTypes: [.folder]) { result in\n            handleFileImport(result: result, isSource: true)\n        }\n        .fileImporter(isPresented: $showDestinationImporter, allowedContentTypes: [.folder]) { result in\n            handleFileImport(result: result, isSource: false)\n        }\n    }\n    \n    private func handleFileImport(result: Result<URL, Error>, isSource: Bool) {\n        do {\n            let url = try result.get()\n            if isSource {\n                viewModel.selectSourceURL(url)\n            } else {\n                viewModel.destinationURL = url\n            }\n        } catch {\n            // Handle error, e.g., show an alert\n            print(\"Error selecting folder: \\(error.localizedDescription)\")\n        }\n    }\n}\n\n// MARK: - Wizard Steps as Subviews\nextension OrganizerWizardView {\n    \n    @ViewBuilder\n    private func step1_SelectSourceAndDestination() -> some View {\n        VStack(alignment: .leading, spacing: 20) {\n            Text(\"Passo 1: Defina a Origem e o Destino\")\n                .font(.title2)\n                .fontWeight(.semibold)\n\n            // Source Folder\n            Text(\"De onde vêm os seus ficheiros?\").font(.headline)\n            HStack {\n                Button(\"📂 Selecionar Pasta de Origem...\") { showSourceImporter = true }\n                if let sourceURL = viewModel.sourceURL {\n                    Text(\"\\(sourceURL.lastPathComponent) (\u{1b}[32m\\(viewModel.sourceFileCount) itens\u{1b}[0m)\")\n                        .font(.callout)\n                        .foregroundColor(.secondary)\n                }\n            }\n            \n            // Destination Folder\n            Text(\"Para onde devem ir os ficheiros?\").font(.headline)\n            HStack {\n                Button(\"📂 Selecionar Pasta de Destino...\") { showDestinationImporter = true }\n                if let destURL = viewModel.destinationURL {\n                    Text(destURL.lastPathComponent)\n                        .font(.callout)\n                        .foregroundColor(.secondary)\n                }\n            }\n            \n            Spacer()\n            \n            HStack {\n                Button(\"Cancelar\") { isPresented = false }\n                Spacer()\n                Button(\"Continuar →\") {\n                    viewModel.currentStep = .chooseActionAndRules\n                    viewModel.generatePreview()\n                }\n                .disabled(viewModel.sourceURL == nil || viewModel.destinationURL == nil)\n            }\n        }\n        .padding(30)\n    }\n    \n    @ViewBuilder\n    private func step2_ChooseActionAndRules() -> some View {\n        VStack(alignment: .leading, spacing: 20) {\n            Text(\"Passo 2: Escolha a Ação e as Regras\")\n                .font(.title2)\n                .fontWeight(.semibold)\n            \n            // Operation Mode\n            Text(\"Ação a executar:\").font(.headline)\n            Picker(\"Ação\", selection: $viewModel.operationMode) {\n                Text(\"Copiar Ficheiros (Recomendado, mais seguro)\").tag(Organizer.OperationMode.copy)\n                Text(\"Mover Ficheiros (Apaga originais após verificação)\").tag(Organizer.OperationMode.move)\n            }\n            .pickerStyle(.radioGroup)\n            \n            Text(\"ℹ️ Ao Mover, verificamos a integridade de cada ficheiro para garantir que não há corrupção.\")\n                .font(.caption)\n                .foregroundColor(.secondary)\n                .padding(.leading, 10)\n            \n            // Folder Structure\n            Text(\"Estrutura das Pastas de Destino:\").font(.headline)\n            Toggle(\"Agrupar por Ano (ex: /2023)\", isOn: $viewModel.groupByYear)\n            Toggle(\"Agrupar por Mês (ex: /10-Out)\", isOn: $viewModel.groupByMonth)\n                .padding(.leading, 20)\n                .disabled(!viewModel.groupByYear)\n            \n            Text(\"Pré-visualização da estrutura:\")\n                .font(.caption).foregroundColor(.secondary).padding(.top)\n            Text(viewModel.fileStructurePreview)\n                .font(.system(.body, design: .monospaced))\n                .padding(10)\n                .background(Color.gray.opacity(0.1))\n                .cornerRadius(5)\n            \n            Spacer()\n            \n            HStack {\n                Button(\"← Voltar\") { viewModel.currentStep = .selectSourceAndDestination }\n                Spacer()\n                Button(\"Pré-visualizar Organização →\") { viewModel.currentStep = .preview }\n            }\n        }\n        .padding(30)\n        .onChange(of: viewModel.groupByYear) { _ in viewModel.generatePreview() }\n        .onChange(of: viewModel.groupByMonth) { _ in viewModel.generatePreview() }\n    }\n    \n    @ViewBuilder\n    private func step3_Preview() -> some View {\n        VStack(alignment: .leading, spacing: 15) {\n            Text(\"Passo 3: Pré-visualização Final\")\n                .font(.title2)\n                .fontWeight(.semibold)\n\n            VStack(alignment: .leading, spacing: 5) {\n                Text(\"**Ação:** \\(viewModel.operationMode == .move ? \"MOVER\" : \"COPIAR\") \\(viewModel.sourceFileCount) ficheiros\")\n                Text(\"**Origem:** \\(viewModel.sourceURL?.path ?? \"N/A\")\")\n                Text(\"**Destino:** \\(viewModel.destinationURL?.path ?? \"N/A\")\")\n            }\n            .padding()\n            .background(Color.blue.opacity(0.1))\n            .cornerRadius(8)\n\n            Text(\"Estrutura de Pastas Resultante (exemplo):\")\n                .font(.headline)\n            \n            Text(viewModel.fileStructurePreview)\n                .font(.system(.body, design: .monospaced))\n                .frame(maxWidth: .infinity, alignment: .leading)\n                .padding()\n                .background(Color.gray.opacity(0.1))\n                .cornerRadius(8)\n            \n            if viewModel.operationMode == .move {\n                HStack {\n                    Image(systemName: \"exclamationmark.triangle.fill\")\n                        .foregroundColor(.orange)\n                    Text(\"Esta ação irá APAGAR os ficheiros originais após uma cópia bem-sucedida.\")\n                }\n                .padding()\n                .background(Color.orange.opacity(0.1))\n                .cornerRadius(8)\n            }\n\n            Spacer()\n            \n            HStack {\n                Button(\"← Voltar\") { viewModel.currentStep = .chooseActionAndRules }\n                Spacer()\n                Button(\"✅ Iniciar Organização\") {\n                    Task {\n                        await viewModel.startOrganization()\n                    }\n                }\n                .keyboardShortcut(.defaultAction)\n            }\n        }\n        .padding(30)\n    }\n    \n    @ViewBuilder\n    private func step4_Progress() -> some View {\n        VStack(spacing: 20) {\n            Text(\"A Organizar os seus ficheiros...\")\n                .font(.title2)\n                .fontWeight(.semibold)\n            \n            ProgressView(value: viewModel.progress)\n                .progressViewStyle(.linear)\n            \n            Text(viewModel.progressMessage)\n                .font(.callout)\n                .foregroundColor(.secondary)\n            \n            Spacer()\n        }\n        .padding(30)\n    }\n    \n    @ViewBuilder\n    private func step5_Complete() -> some View {\n        VStack(spacing: 20) {\n            Text(\"🎉 Sucesso!\")\n                .font(.largeTitle)\n                .fontWeight(.bold)\n                .foregroundColor(.green)\n            \n            Text(\"\\(viewModel.sourceFileCount) ficheiros foram organizados com segurança.\")\n            \n            if let destURL = viewModel.destinationURL {\n                Button(\"Abrir Pasta de Destino\") {\n                    NSWorkspace.shared.open(destURL)\n                }\n            }\n            \n            Spacer()\n            \n            HStack {\n                Spacer()\n                Button(\"Concluir\") {\n                    viewModel.reset()\n                    isPresented = false\n                }\n                .keyboardShortcut(.defaultAction)\n                Spacer()\n            }\n        }\n        .padding(30)\n    }\n}\n